from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build sentence parts in a logical order
    sentence_parts = []

    # Start with main subject and identity
    identity = [main_subject]
    if 'nationality' in predicate_map:
        identity.append(f"is a {predicate_map['nationality'][0]} politician")
    elif 'profession' in predicate_map:
        identity.append(f"is a {predicate_map['profession'][0]}")

    if 'party' in predicate_map:
        identity.append(f"from the {predicate_map['party'][0]} party")

    if len(identity) > 1:
        sentence_parts.append(f"{identity[0]} {' '.join(identity[1:])}")
    else:
        sentence_parts.append(main_subject)

    # Birth information
    birth_info = []
    if 'birthDate' in predicate_map:
        birth_info.append(f"born on {predicate_map['birthDate'][0]}")
    elif 'birthYear' in predicate_map:
        birth_info.append(f"born in {predicate_map['birthYear'][0]}")
    if 'birthPlace' in predicate_map:
        birth_info.append(f"in {predicate_map['birthPlace'][0]}")

    if birth_info:
        sentence_parts.append(f", {' '.join(birth_info)}")

    # Career information
    career_info = []
    if 'office' in predicate_map:
        career_info.append(f"who served as {predicate_map['office'][0]}")
    if 'inOfficeWhilePresident' in predicate_map:
        career_info.append(f"during the presidency of {predicate_map['inOfficeWhilePresident'][0]}")
    if 'inOfficeWhilePrimeMinister' in predicate_map:
        career_info.append(f"during the prime ministership of {predicate_map['inOfficeWhilePrimeMinister'][0]}")
    if 'inOfficeWhileGovernor' in predicate_map:
        career_info.append(f"during the governorship of {predicate_map['inOfficeWhileGovernor'][0]}")
    if 'inOfficeWhileMonarch' in predicate_map:
        career_info.append(f"during the reign of {predicate_map['inOfficeWhileMonarch'][0]}")
    if 'inOfficeWhileVicePresident' in predicate_map:
        career_info.append(f"during the vice presidency of {predicate_map['inOfficeWhileVicePresident'][0]}")
    if 'predecessor' in predicate_map:
        career_info.append(f"previously held by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        career_info.append(f"succeeded by {predicate_map['successor'][0]}")
    if 'hasDeputy' in predicate_map:
        career_info.append(f"with deputy {predicate_map['hasDeputy'][0]}")

    if career_info:
        sentence_parts.append(f", {' '.join(career_info)}")

    # Military service
    military_info = []
    if 'militaryBranch' in predicate_map:
        military_info.append(f"served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        military_info.append(f"with rank {predicate_map['militaryRank'][0]}")
    if 'battle' in predicate_map:
        military_info.append(f"participated in the {predicate_map['battle'][0]}")
    if 'unit' in predicate_map:
        military_info.append(f"with {predicate_map['unit'][0]} unit")

    if military_info:
        sentence_parts.append(f", {' '.join(military_info)}")

    # Education
    if 'almaMater' in predicate_map:
        sentence_parts.append(f", studied at {predicate_map['almaMater'][0]}")

    # Personal information
    personal_info = []
    if 'spouse' in predicate_map:
        personal_info.append(f"married to {predicate_map['spouse'][0]}")
    if 'residence' in predicate_map:
        personal_info.append(f"residing in {predicate_map['residence'][0]}")
    if 'religion' in predicate_map:
        personal_info.append(f"of {predicate_map['religion'][0]} faith")
    if 'award' in predicate_map:
        personal_info.append(f"received the {predicate_map['award'][0]}")

    if personal_info:
        sentence_parts.append(f", {' '.join(personal_info)}")

    # Location information
    location_info = []
    if 'country' in predicate_map:
        location_info.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        location_info.append(f"in {predicate_map['state'][0]}")
    if 'region' in predicate_map:
        location_info.append(f"region {predicate_map['region'][0]}")

    if location_info:
        sentence_parts.append(f", {' '.join(location_info)}")

    # Death information
    death_info = []
    if 'deathDate' in predicate_map:
        death_info.append(f"died on {predicate_map['deathDate'][0]}")
    elif 'deathYear' in predicate_map:
        death_info.append(f"died in {predicate_map['deathYear'][0]}")
    if 'deathPlace' in predicate_map:
        death_info.append(f"in {predicate_map['deathPlace'][0]}")

    if death_info:
        sentence_parts.append(f", {' '.join(death_info)}")

    # Join and format the final sentence
    result = ' '.join(sentence_parts)
    return result + "."

# EVOLVE-BLOCK-END

